#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define NX 512
#define NY 512
#define NZ 512
#define STEPS 100

void iso2dfd(float* __restrict__ A, float* __restrict__ B, int nx, int ny, int nz) {
    #pragma omp parallel for collapse(3)
    for (int z = 1; z < nz - 1; z++) {
        for (int y = 1; y < ny - 1; y++) {
            for (int x = 1; x < nx - 1; x++) {
                int idx = z * ny * nx + y * nx + x;
                B[idx] = (A[idx - nx * ny] + A[idx + nx * ny] + A[idx - nx] + A[idx + nx] + A[idx - 1] + A[idx + 1] - 6.0f * A[idx]) / 6.0f;
            }
        }
    }
}

int main() {
    int nx = NX, ny = NY, nz = NZ;
    size_t size = nx * ny * nz * sizeof(float);

    float* A = (float*)malloc(size);
    float* B = (float*)malloc(size);

    // Initialize A with some values
    for (int i = 0; i < nx * ny * nz; i++) {
        A[i] = static_cast<float>(i % 100);
    }

    for (int t = 0; t < STEPS; t++) {
        iso2dfd(A, B, nx, ny, nz);
        // Swap pointers
        float* temp = A;
        A = B;
        B = temp;
    }

    // Print some output to verify
    printf("%f\n", A[(nz/2)*ny*nx + (ny/2)*nx + (nx/2)]);

    free(A);
    free(B);

    return 0;
}
